import { Injectable, NotFoundException } from '@nestjs/common';

import { BuybackSetting, SettingEntity, SettingKey, Settings } from '@/db';
import { TransactionalAdapterTypeOrm } from '@/modules/global';
import { TransactionHost } from '@nestjs-cls/transactional';
import { BuybackFeesDto } from '@/api/admin/settings/dtos/buyback-fees.dto';

@Injectable()
export class SettingsService {
  constructor(
    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
  ) {}

  async getOne<T extends SettingKey>(key: T): Promise<Settings[T]> {
    const settingRepository = this.txHost.tx.getRepository(SettingEntity);

    const setting = await settingRepository.findOne({
      where: { key },
    });

    if (!setting) {
      throw new NotFoundException('Setting not found');
    }

    return setting.value.data as Settings[T];
  }

  async upsertOne(key: SettingKey, value: Settings[SettingKey]) {
    const settingRepository = this.txHost.tx.getRepository(SettingEntity);

    return settingRepository.upsert(
      {
        key,
        value: { data: value },
      },
      ['key'],
    );
  }

  /**
   * Update buyback settings by merging with existing settings.
   * Only updates the provided fields, preserving existing values for others.
   */
  async updateBuybackSettings(dto: Partial<BuybackSetting>): Promise<void> {
    const currentSettings = await this.getOne(SettingKey.Buyback);

    // Merge updates with existing settings
    const updatedSettings = {
      ...currentSettings,
      ...dto, // Only updates provided fields
    };

    await this.upsertOne(SettingKey.Buyback, updatedSettings);
  }

  /**
   * Update buyback fees by merging with existing settings.
   * Only updates the provided fee fields, preserving existing values for others.
   */
  async updateBuybackFees(dto: BuybackFeesDto): Promise<void> {
    const currentSettings = await this.getOne(SettingKey.Buyback);

    // Merge fee updates with existing settings
    const updatedSettings = {
      ...currentSettings,
      ...dto, // Only updates provided fee fields
    };

    await this.upsertOne(SettingKey.Buyback, updatedSettings);
  }
}

